import json
import pymysql
import os

def lambda_handler(event, context):
    db_host = os.environ.get('DB_HOST')
    db_user = os.environ.get('DB_USER')
    db_password = os.environ.get('DB_PASSWORD')
    db_name = os.environ.get('DB_NAME')
    
    connection = None
    
    try:
        connection = pymysql.connect(
            host=db_host,
            user=db_user,
            password=db_password,
            database=db_name,
            charset='utf8mb4',
            cursorclass=pymysql.cursors.DictCursor
        )
        
        query_params = {}
        if event.get('queryStringParameters'):
            query_params = event['queryStringParameters']
        elif event.get('body'):
            query_params = json.loads(event['body'])
        
        sql_query, sql_params = build_search_query(query_params)
        
        with connection.cursor() as cursor:
            cursor.execute(sql_query, sql_params)
            results = cursor.fetchall()
        
        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'success': True,
                'count': len(results),
                'products': results
            }, default=str)
        }
        
    except pymysql.MySQLError as e:
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'success': False,
                'error': f'Database error: {str(e)}'
            })
        }
    
    except Exception as e:
        return {
            'statusCode': 400,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'success': False,
                'error': str(e)
            })
        }
    
    finally:
        if connection:
            connection.close()


def build_search_query(params):
    base_query = "SELECT * FROM products WHERE 1=1"
    conditions = []
    sql_params = []
    
    if params.get('name'):
        conditions.append("name LIKE %s")
        sql_params.append(f"%{params['name']}%")
    
    if params.get('category'):
        conditions.append("category = %s")
        sql_params.append(params['category'])
    
    if params.get('min_price'):
        conditions.append("price >= %s")
        sql_params.append(float(params['min_price']))
    
    if params.get('max_price'):
        conditions.append("price <= %s")
        sql_params.append(float(params['max_price']))
    
    if params.get('brand'):
        conditions.append("brand = %s")
        sql_params.append(params['brand'])
    
    if params.get('in_stock'):
        if params['in_stock'].lower() in ['true', '1', 'yes']:
            conditions.append("stock_quantity > 0")
    
    if params.get('status'):
        conditions.append("status = %s")
        sql_params.append(params['status'])
    
    if params.get('sku'):
        conditions.append("sku = %s")
        sql_params.append(params['sku'])
    
    if params.get('description'):
        conditions.append("description LIKE %s")
        sql_params.append(f"%{params['description']}%")
    
    if params.get('tags'):
        conditions.append("tags LIKE %s")
        sql_params.append(f"%{params['tags']}%")
    
    if params.get('created_after'):
        conditions.append("created_at >= %s")
        sql_params.append(params['created_after'])
    
    if params.get('created_before'):
        conditions.append("created_at <= %s")
        sql_params.append(params['created_before'])
    
    if params.get('updated_after'):
        conditions.append("updated_at >= %s")
        sql_params.append(params['updated_after'])
    
    if params.get('rating_min'):
        conditions.append("rating >= %s")
        sql_params.append(float(params['rating_min']))
    
    if params.get('rating_max'):
        conditions.append("rating <= %s")
        sql_params.append(float(params['rating_max']))
    
    for condition in conditions:
        base_query += f" AND {condition}"
    
    order_by = params.get('order_by', 'id')
    order_direction = params.get('order_direction', 'ASC').upper()
    
    if order_direction not in ['ASC', 'DESC']:
        order_direction = 'ASC'
    
    allowed_order_columns = ['id', 'name', 'price', 'created_at', 'updated_at', 'rating', 'stock_quantity']
    if order_by in allowed_order_columns:
        base_query += f" ORDER BY {order_by} {order_direction}"
    else:
        base_query += " ORDER BY id ASC"
    
    limit = int(params.get('limit', 100))
    offset = int(params.get('offset', 0))
    
    if limit > 1000:
        limit = 1000
    
    base_query += " LIMIT %s OFFSET %s"
    sql_params.extend([limit, offset])
    
    return base_query, sql_params